import styles from './styles.module.scss';
import Image from 'next/image';
import Link from 'next/link';

export default function Facebook() {
    return (
        <Link href="/auth/facebook" className={styles.facebookButton}> {/* Giả sử đường dẫn đăng nhập Facebook là /auth/facebook */}
            <Image
                src="../Facebook.svg" // Đường dẫn đến ảnh logo Facebook
                alt="Đăng nhập bằng Facebook"
                width={24}  // Kích thước logo
                height={24}
            />
            <span>Đăng nhập bằng Facebook</span>
        </Link>
    );
}